import React from 'react';
import './Stock.css'

function DisplayStockData({ stockData }) {
  if (!stockData) {
    return <p>ENTER STOCK</p>;
  }
  const arrow = stockData.change > 0 ? '\u25B2' : '\u25BC';
  const mp = stockData.change > 0 ? '\x2b' : '\u2212';
  const isStockUp = stockData.change > 0;
  const Change = Math.abs(stockData.change);

  function moveStocks() {
    const stocksContainer = document.querySelector('.info-container');
    const stocks = stocksContainer.querySelectorAll('.info');
    const totalWidth = Array.from(stocks).reduce(
      (acc, stock) => acc + stock.offsetWidth,
      0
    );
    const containerWidth = stocksContainer.offsetWidth;
    
    let currentPosition = 0;
    let isMovingRight = false;
    
    function move() {
      currentPosition += isMovingRight ? -1 : 1;
      stocksContainer.style.transform = `translateX(${currentPosition}px)`;
      
      if (currentPosition <= -totalWidth + containerWidth) {
        isMovingRight = true;
      } else if (currentPosition >= 0) {
        isMovingRight = false;
      }
      
      requestAnimationFrame(move);
    }
    
    move();
  }
  
  return (

        <div className='info'>
          <div>
            <p style={{color: isStockUp ? "lightgreen" : "red"}}>{stockData.symbol}</p>
            <p style={{color: isStockUp ? "lightgreen" : "red"}}>{stockData.price}</p>
          </div>
          <div>
            <p style={{color: isStockUp ? "lightgreen" : "red"}}>{arrow}{stockData.pChange}</p>
            <p style={{color: isStockUp ? "lightgreen" : "red"}}>&thinsp;{mp}&thinsp;{Change}</p>
          </div>
        </div>
  );
}

export default DisplayStockData;
